mapper.select:
SELECT c.corporation_cd, c.corporation_nm, COALESCE(c.corporation_info->>'business_no', '') AS business_no, COALESCE(c.corporation_info->>'ceo_nm', '') AS ceo_nm, COALESCE(c.corporation_info->>'address', '') AS address, COALESCE(c.corporation_info->>'tel_no', '') AS tel_no, COALESCE(c.corporation_info->>'fax_no', '') AS fax_no, COALESCE(c.corporation_info->>'email', '') AS email, COALESCE(c.corporation_info->>'homepage_url', '') AS homepage_url, COALESCE(c.corporation_info->>'remark', '') AS remark, c.is_active AS active, c.created_at, c.updated_at, COALESCE(c.created_by, '') AS created_by, COALESCE(c.updated_by, '') AS updated_by FROM om_corporation_m c ORDER BY
c.corporation_nm ${sortDirection} c.created_at ${sortDirection} c.corporation_cd ${sortDirection}
LIMIT #{limit} OFFSET #{offset}
